// Generated by generate.ts — hidden adversarial suite for unique.
// Run via `npx tsx __audit__/unique.hidden.ts` inside the scratch project.
import { unique, uniqueBy } from '../src/unique'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("removes duplicates", unique([1,2,1,3,2]), [1,2,3])
await check("empty", unique([]), [])
await check("no duplicates", unique([1,2,3]), [1,2,3])
await check("all same", unique([1,1,1]), [1])
await check("strings", unique(["a","b","a","c"]), ["a","b","c"])
await check("uniqueBy field", uniqueBy([{n:1,v:"a"},{n:2,v:"b"},{n:1,v:"c"}], x=>x.n), [{"n":1,"v":"a"},{"n":2,"v":"b"}])
await check("uniqueBy length", uniqueBy(["a","bb","c","dd"], s=>s.length), ["a","bb"])
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
